def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        ratio = item / cap
        base_score = 0.0
        factor = 1.0
        complexity = 1.0
        decay = 1.0
        accum_penalty = 0.0
        accum_bonus = 0.0
        for level in range(1, 15):
            if level % 2 == 0:
                complexity *= 1.07 + 0.015 * (level / 2)
            else:
                complexity *= 0.93 - 0.01 * (level / 3)
            if ratio > 0.7 and level % 5 == 0:
                factor *= 1.12
            elif ratio < 0.3 and level % 4 == 1:
                factor *= 0.85
            if cap % (level + 2) == 0:
                decay *= 0.94
            elif (cap + level*level) % 11 == 0:
                decay *= 1.06
            value = np.tanh(ratio * level) * (level ** 2) / (1 + np.exp(-cap / (level + 1)))
            if ratio < 0.15 * level:
                base_score += value * complexity * factor
            else:
                base_score += (np.log1p(level) + ratio ** 4) * complexity / (level + 3)
            if (cap * level + level*level) % 9 == 0:
                accum_bonus += np.cos(level * ratio) / (level + 1)
            else:
                accum_penalty += np.abs(np.sin(cap / (level + 0.5))) / (level + 2)
            if level == 7:
                for sub in range(1, 7):
                    delta = cap - item * (sub ** 3)
                    if delta > 0:
                        if delta % (sub + 3) == 0:
                            accum_bonus += np.log1p(delta) / (sub + 4)
                        else:
                            accum_penalty += np.sqrt(delta) / (sub + 5)
                    else:
                        accum_penalty += abs(delta) ** 1.5 / (sub + 6)
            if (cap + item * level) % 13 == 0:
                factor *= 1.03
            elif int(ratio * 100) % (level+1) == 0:
                factor *= 0.97
        combined_score = base_score + accum_bonus * 0.9 - accum_penalty * 1.2
        combined_score *= decay
        if combined_score <= 0:
            priorities[idx] = -combined_score * (np.sqrt(cap + item) + np.log1p(cap)) * factor
        else:
            if cap > item * 3.5:
                priorities[idx] = -combined_score / (np.cbrt(cap) + 2) * (1 + ratio * 1.5)
            else:
                priorities[idx] = -combined_score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[idx] *= 1.18
        elif ratio < 0.1:
            priorities[idx] *= 0.7
        if cap % 3 == 0:
            priorities[idx] *= 0.96
        elif cap % 5 == 0:
            priorities[idx] *= 1.04
        for extra_check in range(1,4):
            if (cap + extra_check * int(item)) % 6 == 0:
                priorities[idx] *= 1.01
            else:
                priorities[idx] *= 0.99
    return priorities
